    const responseExcerpt = clipAgentText(stepResult.response ?? '', 4000);
    const summaryLines = [
      `[agent] "${input.slice(0, 120)}" — ${normalizedStatus}`,
      `Engine: ${engineId}`,
      `Turns: ${stats.turnsUsed}`,
      `Tool calls: ${stats.totalToolCalls}`,
      `Tokens: ${stats.tokensUsed}`,
      `Elapsed: ${(stats.elapsedMs / 1000).toFixed(0)}s`,
    ];
    if (stepResult.error && stepResult.stopReason !== 'completed') summaryLines.push(`Error: ${stepResult.error}`);
    if (responseExcerpt) summaryLines.push(`Final response:\n${responseExcerpt}`);
    const summary = summaryLines.join('\n');
