export interface RunAgentTeamOptions {
  engines?: string[];
  taskKind?: 'edit'|'investigate';
  maxTurns?: number;
  maxDurationMs?: number;
  maxTeamCostUsd?: number;
  fitnessCmd?: string;
  systemPrompt?: string;
  parentSignal?: AbortSignal;
  synthesize?: boolean;
  synthesisTimeoutSec?: number;
  shadowMode?: boolean;
  foregroundEngineId?: string;
}

/**
 * Run an autonomous agent team: N AgentSession instances in N worktrees with shared budget, synthesis, and explicit transcript events. Used by Cesar-driven team mode and by /agent-team slash command. Wraps AgentTeam from core/cesar/agent-team.kern.
 */
// @kern-source: agent:492
export async function runAgentTeam(input: string, dispatch: Dispatch, ctx: HandlerContext, opts?: RunAgentTeamOptions): Promise<AgentContinuationResult|null> {
  const abort = new AbortController();
  // ── Resolve members ───────────────────────────────────────
  const available = ctx.activeEngines();
  if (available.length === 0) {
    dispatch({ type: 'error', message: 'No engines available for agent team mode.' });
    return null;
  }

  // Pick engines: caller-specified or auto-select first 3 active API engines.
  const requestedEngines = opts?.engines ?? null;
  const memberEngineIds: string[] = [];
  const memberEngines: EngineDefinition[] = [];

  if (requestedEngines && requestedEngines.length > 0) {
    for (const id of requestedEngines) {
      if (!available.includes(id)) {
        dispatch({ type: 'error', message: `Engine ${id} is not active. Available: ${available.join(', ')}` });
        return null;
      }
      try {
        const eng = ctx.registry.get(id);
        if (!eng.api) {
          dispatch({ type: 'error', message: `Engine ${id} has no API config — agent team mode requires API engines.` });
          return null;
        }
        memberEngineIds.push(id);
        memberEngines.push(eng);
      } catch (err) {
        dispatch({ type: 'error', message: `Engine ${id}: ${err instanceof Error ? err.message : String(err)}` });
        return null;
      }
    }
  } else {
    const MAX_AUTO = 3;
    for (const id of available) {
      if (memberEngines.length >= MAX_AUTO) break;
      try {
        const eng = ctx.registry.get(id);
        if (eng.api) {
          memberEngineIds.push(id);
          memberEngines.push(eng);
        }
      } catch { /* skip */ }
    }
    if (memberEngines.length === 0) {
      dispatch({ type: 'error', message: `Agent team mode requires API engines. Active: ${available.join(', ')}` });
      return null;
    }
    if (memberEngines.length === 1) {
      // Only one API engine available — fall back to solo agent mode.
      dispatch({ type: 'warning', message: `Only one API engine available (${memberEngineIds[0]}); falling back to solo agent mode.` });
      return await runAgentMode(input, dispatch, ctx, { engineId: memberEngineIds[0], maxTurns: opts?.maxTurns, maxDurationMs: opts?.maxDurationMs, systemPrompt: opts?.systemPrompt, parentSignal: opts?.parentSignal });
    }
  }

  // RT-22: complexity floor for auto-fanout. If the input is suspiciously
  // small for team mode, downgrade to solo. Cesar might over-fan-out via
  // the playbook; this is the runtime backstop.
  if (input.length < 30 && requestedEngines === null) {
    dispatch({ type: 'warning', message: `Input too short for team mode (${input.length} chars); falling back to solo agent.` });
    // Review #7: thread parentSignal through so plan-mode Ctrl+C reaches
    // the solo fallback. Previously the signal was dropped here.
    return await runAgentMode(input, dispatch, ctx, { maxTurns: opts?.maxTurns, maxDurationMs: opts?.maxDurationMs, systemPrompt: opts?.systemPrompt, parentSignal: opts?.parentSignal });
  }

  // ── Build team config ─────────────────────────────────────
  const budget: AgentBudget = {
    maxTurns: opts?.maxTurns ?? 10,
    maxDurationMs: opts?.maxDurationMs ?? 600_000,
  };
  const cwd = resolveWorkingDir();
  const taskKind: 'edit'|'investigate' = opts?.taskKind ?? 'edit';
  let followUp: AgentContinuationResult | null = null;

  // Optional ContextThread continuity — shared across all team members only
  // when the user opts into cross-session memory.
  let teamThread: import('@agon/core').ContextThread | undefined;
  if ((ctx.config as any).sessionContinuity === true) {
    try {
      teamThread = loadOrCreateActiveThread(cwd, opts?.systemPrompt);
    } catch (threadErr) {
      console.warn(`[agon] context-thread: failed to load active thread for team (running without context): ${threadErr instanceof Error ? threadErr.message : String(threadErr)}`);
    }
  }

  const members: AgentTeamMemberConfig[] = memberEngines.map((eng, i) => ({
    engineId: memberEngineIds[i],
    api: eng.api!,
    systemPrompt: opts?.systemPrompt,
    contextWindowTokens: (eng.api as any)?.contextWindow ?? (eng as any).contextWindow,
  }));

  // RT-12 cost guard: build a costFn that maps engineId → tokens → USD.
  const enginesById = new Map<string, EngineDefinition>(memberEngineIds.map((id, i) => [id, memberEngines[i]]));
  const costFn = (engineId: string, tokensUsed: number): number => {
    const eng = enginesById.get(engineId);
    if (!eng) return 0;
    return estimatedTokensToCost(eng, tokensUsed);
  };

  const teamConfig: AgentTeamConfig = {
    members,
    cwd,
    budget,
    isolate: true,  // always isolate for team mode — concurrent file edits would clobber
    teamBudget: {
      maxTeamCostUsd: opts?.maxTeamCostUsd ?? 3.00,  // hard ceiling
      maxTeamWallClockMs: 15 * 60 * 1000,            // 15 min
    },
    costFn,
    heavyToolSemaphorePermits: 1,  // serialize heavy tools across members (RT-26)
    thread: teamThread,  // shared ContextThread — all members share the same history
    permissionMode: (ctx.config as any).permissionMode ?? 'ask',
    allowedCommands: (ctx.config as any).allowedCommands ?? [],
    toolPermissions: (ctx.config as any).toolPermissions ?? {},
    onPermissionAsk: (engineId: string, tool: string, command: string, reason: string) =>
      buildAgentApprovalCallback(dispatch, ctx, engineId)(tool, command, reason),
  };

  // ── Wire abort BEFORE creating team — RT-11 fix ───────────
  // The original /agent had a race between the early abort.signal.aborted
  // check and addEventListener. Here we do the listener first, then the
  // early check — there's no window where an abort can be missed.
  let team: AgentTeam | null = null;
  let teamCancelled = false;
  const onAbort = () => {
    teamCancelled = true;
    if (team) team.cancel();
  };
  abort.signal.addEventListener('abort', onAbort);

  // Codex P1: when called from a plan step, the caller owns the active
  // abort. Bridge parentSignal → internal abort and DO NOT touch
  // ctx.setActiveAbort so the plan executor's controller stays intact.
  const parentSignal = opts?.parentSignal;
  let onParentAbort: (() => void) | null = null;
  if (parentSignal) {
    if (parentSignal.aborted) {
      try { abort.abort(); } catch { /* ignore */ }
    } else {
      onParentAbort = () => { try { abort.abort(); } catch { /* ignore */ } };
      parentSignal.addEventListener('abort', onParentAbort);
    }
  } else {
    ctx.setActiveAbort(abort);
  }

  if (abort.signal.aborted) {
    // Already cancelled before we even got here.
    if (!parentSignal) ctx.setActiveAbort(null);
    if (onParentAbort && parentSignal) {
      try { parentSignal.removeEventListener('abort', onParentAbort); } catch { /* ignore */ }
    }
    abort.signal.removeEventListener('abort', onAbort);
    return {
      kind: 'team-agent',
      status: 'cancelled',
      task: input,
      taskKind,
      summary: `[team-agent] "${input.slice(0, 120)}" — cancelled before start`,
      engineId: null,
      winnerId: null,
      response: null,
      patchPath: null,
      patchAvailable: false,
      workspaceChangedInPlace: false,
    };
  }

  try {
    // ── Create + initialize team ──────────────────────────
    team = new AgentTeam(teamConfig);
    await team.initialize();

    if (teamCancelled || abort.signal.aborted) {
      // OpenCode review fix #1: dispatch a user-visible event so the user
      // knows the cancel landed during initialize. Otherwise the run would
      // silently disappear with no transcript record. Worktrees may have
      // been created (consuming disk + git activity) so the user should
      // see "team cancelled before start" rather than nothing.
      dispatch({ type: 'warning', message: `Agent team cancelled during initialize \u2014 worktrees rolled back` });
      await team.cleanup();
      return {
        kind: 'team-agent',
        status: 'cancelled',
        task: input,
        taskKind,
        summary: `[team-agent] "${input.slice(0, 120)}" — cancelled during initialize`,
        engineId: null,
        winnerId: null,
        response: null,
        patchPath: null,
        patchAvailable: false,
        workspaceChangedInPlace: false,
      };
    }

    const teamId = team.getRunId();
    const shadowMode = opts?.shadowMode === true;
    const foregroundEngineId = opts?.foregroundEngineId ?? memberEngineIds[0];

    // ── Emit team-start ───────────────────────────────────
    dispatch({
      type: 'agent-team-start',
      teamId,
      engineIds: memberEngineIds,
      task: input,
      taskKind,
    });

    // Pre-emit step-start for each member so the UI shows N panels
    // immediately, before the first AgentEvent arrives.
    for (const id of memberEngineIds) {
      if (shadowMode && id !== foregroundEngineId) continue;
      dispatch({
        type: 'agent-step-start',
        engineId: id,
        turnIndex: 0,
        userPrompt: input,
        maxTurns: budget.maxTurns,
        maxDurationMs: budget.maxDurationMs,
        maxTokens: budget.maxTokens ?? null,
        teamId,
      });
    }

    // Phase C/D: StreamBridge + shadow-mode filtering.
    // In normal team mode, all engines' events reach the user.
    // In shadow mode (Phase D), only the foreground engine's events are
    // bridged to the visible dispatch — shadow engines run silently in
    // background worktrees and their output is suppressed until post-step
    // comparison. If a shadow wins, we emit engine-switch and surface the
    // winning patch through the normal review block.

    // In shadow mode, suppress dispatch for non-foreground engines by
    // wrapping the dispatch function to drop events from shadow engines.
    const shadowFilteredDispatch = shadowMode
      ? (event: Record<string,unknown>) => {
          // Pass through events that don't carry an engineId (structural events)
          // or events from the foreground engine.
          const eid = (event as any).engineId;
          if (!eid || eid === foregroundEngineId) {
            (dispatch as (e: Record<string,unknown>) => void)(event);
          }
          // Shadow engine events are silently dropped during the step.
        }
      : dispatch as (event: Record<string,unknown>) => void;

    const teamBridge = createStreamBridge(shadowFilteredDispatch, {
      initialEngineId: foregroundEngineId,
    });
    const onEvent = teamBridge.makeOnEvent();

    // ── Run the team ──────────────────────────────────────
    const teamResult = await team.step(input, { onEvent });

    // Codex review fix (P1): post-step cancellation guard. If the user
    // cancelled mid-run (via Ctrl-C → onAbort → team.cancel()), the team
    // returns with whatever partial results it has. We must NOT proceed
    // to fitness gate, scoring, or patch-review — that would surface a
    // patch from a run the user explicitly aborted.
    if (teamCancelled || abort.signal.aborted) {
      // Emit cancelled step-end events for transcript/UI consistency,
      // then a team-complete with winner=null so the panels clear.
      for (const m of teamResult.members) {
        if (shadowMode && m.engineId !== foregroundEngineId) continue;
        dispatch({
          type: 'agent-step-end',
          engineId: m.engineId,
          turnIndex: 0,
          outcome: 'cancelled',
          toolCalls: m.stepResult?.toolCalls ?? 0,
          tokensUsed: m.stepResult?.tokensUsed ?? 0,
          stopReason: 'cancelled',
        });
        dispatch({ type: 'streaming-end', engineId: m.engineId });
      }
      let cancelCost = 0;
      for (const m of teamResult.members) {
        cancelCost += costFn(m.engineId, m.stepResult?.tokensUsed ?? 0);
      }
      dispatch({
        type: 'agent-team-complete',
        teamId,
        winner: null,
        synthesizedPatch: null,
        synthesizedAnalysis: null,
        memberOutcomes: teamResult.members.map((m) => ({
          engineId: m.engineId,
          outcome: 'cancelled',
          diffLines: 0,
          passedFitness: false,
        })),
        teamCostUsd: cancelCost,
        teamDurationMs: teamResult.durationMs,
      });
      dispatch({ type: 'warning', message: `Agent team cancelled by user \u2014 $${cancelCost.toFixed(2)} spent before cancel` });
      return {
        kind: 'team-agent',
        status: 'cancelled',
        task: input,
        taskKind,
        summary: `[team-agent] "${input.slice(0, 120)}" — cancelled after ${teamResult.members.length} member run(s)`,
        engineId: null,
        winnerId: null,
        response: null,
        patchPath: null,
        patchAvailable: false,
        workspaceChangedInPlace: false,
      };
    }

    // ── Emit step-end for each member ─────────────────────
    for (const m of teamResult.members) {
      if (shadowMode && m.engineId !== foregroundEngineId) continue;
      const outcome: 'completed'|'cancelled'|'failed' =
        !m.stepResult ? 'failed'
        : m.stepResult.stopReason === 'completed' ? 'completed'
        : m.stepResult.stopReason === 'cancelled' ? 'cancelled'
        : 'failed';
      dispatch({
        type: 'agent-step-end',
        engineId: m.engineId,
        turnIndex: 0,
        outcome,
        toolCalls: m.stepResult?.toolCalls ?? 0,
        tokensUsed: m.stepResult?.tokensUsed ?? 0,
        stopReason: m.stepResult?.stopReason ?? 'error',
      });
      dispatch({ type: 'streaming-end', engineId: m.engineId });
    }

    // ── Phase 3 scoring ──────────────────────────────────
    // RT-3 fix: typecheck-or-fail fitness gate before scoring.
    // Gemini code review fix #2: parallelize the fitness gate. Each member
    // has an isolated worktree so the typecheck runs can safely overlap.
    // Sequential for a 3-member team would add ~2 minutes of wall-clock
    // (each typecheck is ~45s on a real codebase) AFTER the agents finish.
    const fitnessPassed = new Map<string, boolean>();
    if (taskKind === 'edit') {
      // FU-2: default to 'npm run typecheck' but warn when used so the
      // user knows the team-agent picked an arbitrary command. A real
      // project-aware default lands in a follow-up — for now an explicit
      // warning is much better than silently running an unrelated command.
      let fitnessCmd = opts?.fitnessCmd;
      if (!fitnessCmd || fitnessCmd.trim().length === 0) {
        fitnessCmd = 'npm run typecheck';
        dispatch({ type: 'warning', message: `team-agent: no fitnessCmd provided; defaulting to '${fitnessCmd}'. Pass an explicit fitnessCmd to verify the right thing.` });
      }
      const fitnessPromises = teamResult.members.map(async (m): Promise<{engineId:string, passed:boolean}> => {
        if (!m.stepResult || m.error || !m.worktreePath) {
          return { engineId: m.engineId, passed: false };
        }
        try {
          const fitnessResult = await spawnWithTimeout({
            command: 'sh',
            args: ['-c', fitnessCmd],
            cwd: m.worktreePath,
            timeout: 60,
          });
          return { engineId: m.engineId, passed: fitnessResult.exitCode === 0 };
        } catch {
          return { engineId: m.engineId, passed: false };
        }
      });
      const settledFitness = await Promise.allSettled(fitnessPromises);
      for (let i = 0; i < settledFitness.length; i++) {
        const outcome = settledFitness[i];
        const id = teamResult.members[i].engineId;
        if (outcome.status === 'fulfilled') {
          fitnessPassed.set(outcome.value.engineId, outcome.value.passed);
        } else {
          fitnessPassed.set(id, false);
        }
      }
    }

    const scored: Map<string, EngineResult> = scoreAgentTeamResult(teamResult, cwd, taskKind, fitnessPassed);
    const winnerInfo = determineWinner(scored, 8);

    // Phase D: in shadow mode, notify the user if a shadow engine beat the
    // foreground. Emit engine-switch so the StreamBridge + UI can show the
    // attribution transition ("claude → gemini (synthesis winner)").
    if (shadowMode && winnerInfo.winner && winnerInfo.winner !== foregroundEngineId) {
      dispatch({
        type: 'engine-switch',
        from: foregroundEngineId,
        to: winnerInfo.winner,
        reason: 'synthesis',
        confidence: winnerInfo.bestScore,
      });
      dispatch({
        type: 'info',
        message: `Shadow worker ${winnerInfo.winner} beat foreground ${foregroundEngineId}; surfacing the shadow result.`,
      });
    }

    // ── Pick winner's initial diff/response ──────────────
    let winnerDiff: string | null = null;
    let winnerAnalysis: string | null = null;
    let synthesisRan = false;
    let synthesisChanged = false;
    if (winnerInfo.winner) {
      const winnerMember = teamResult.members.find((m) => m.engineId === winnerInfo.winner);
      if (winnerMember && winnerMember.worktreePath && taskKind === 'edit') {
        try { winnerDiff = worktreeChangedDiff(winnerMember.worktreePath, teamResult.baseSha); } catch { /* leave null */ }
      }
      if (winnerMember && winnerMember.stepResult && taskKind === 'investigate') {
        winnerAnalysis = winnerMember.stepResult.response;
      }
    }

    // ── RT-25 synthesis: winner-refines-with-elevated-loser-insights ──
    // Re-invoke the winner with full tool access against their worktree,
    // giving them the losers' diffs/reasoning framed so they look for
    // what they MISSED rather than defending what they have. Default-on;
    // opt out with opts.synthesize=false. Cost IS metered now (Codex M4):
    // we estimate tokens from response length and add to teamCost before
    // the team-complete event is emitted. Post-synthesis fitness re-check
    // (Codex H1): if the winner broke the fitness gate mid-synthesis, we
    // revert winnerDiff to its pre-synthesis value.
    let synthesisCostUsd = 0;
    let synthesisFitnessRegressed = false;
    const preSynthesisWinnerDiff = winnerDiff;  // Codex H1: save for rollback
    const preSynthesisWinnerAnalysis = winnerAnalysis;
    const synthesizeOn = opts?.synthesize !== false;
    if (
      synthesizeOn &&
      winnerInfo.winner &&
      !teamCancelled &&
      !abort.signal.aborted
    ) {
      const winnerIdx = memberEngineIds.indexOf(winnerInfo.winner);
      const winnerEngine = winnerIdx >= 0 ? memberEngines[winnerIdx] : null;
      const winnerApi = winnerEngine?.api ?? null;
      const winnerMember = teamResult.members.find((m) => m.engineId === winnerInfo.winner);

      // OpenCode 8.1: explicit dispatch if winner is non-API.
      if (!winnerApi) {
        dispatch({
          type: 'info',
          message: `Synthesis skipped: winner ${winnerInfo.winner} has no API config (non-API engine).`,
        });
      } else if (!winnerMember) {
        // Defensive: should never happen given determineWinner uses scored map from teamResult.
        dispatch({ type: 'info', message: `Synthesis skipped: winner member not found in team result.` });
      } else {
        // Build loser contexts from the worktrees that survived.
        const losers: AgentSynthesisLoser[] = [];
        for (const m of teamResult.members) {
          if (m.engineId === winnerInfo.winner) continue;
          if (!m.stepResult) continue;  // errored or never ran
          let loserDiff = '';
          if (m.worktreePath && taskKind === 'edit') {
            try { loserDiff = worktreeChangedDiff(m.worktreePath, teamResult.baseSha); } catch { /* empty */ }
          }
          losers.push({
            engineId: m.engineId,
            diff: loserDiff,
            response: m.stepResult.response ?? '',
            passedFitness: fitnessPassed.get(m.engineId) ?? false,
          });
        }

        // OpenCode 8.2: explicit dispatch when all losers errored.
        if (losers.length === 0) {
          dispatch({
            type: 'info',
            message: `Synthesis skipped: no other engines have usable results (all errored or no response).`,
          });
        } else if (taskKind === 'edit' && winnerMember.worktreePath && winnerDiff !== null) {
          // OpenCode 8.3: existsSync check before synthesis — worktree
          // may have been cleaned up by a race with external processes.
          if (!existsSync(winnerMember.worktreePath)) {
            dispatch({
              type: 'warning',
              message: `Synthesis skipped: winner's worktree ${winnerMember.worktreePath} no longer exists.`,
            });
          } else {
            dispatch({
              type: 'info',
              message: `Synthesizing: ${winnerInfo.winner} refining with ${losers.length} other engine${losers.length === 1 ? '' : 's'}' insights...`,
            });
            try {
              const synthResult = await runAgentTeamSynthesis({
                task: input,
                winnerEngineId: winnerInfo.winner,
                winnerApi,
                winnerWorktreePath: winnerMember.worktreePath,
                winnerDiff,
                losers,
                baseSha: teamResult.baseSha,
                timeout: opts?.synthesisTimeoutSec ?? 180,
                signal: abort.signal,
                maxSteps: 6,
                // Codex M5: thread winner's systemPrompt so refinement
                // keeps repo-specific constraints and safety rules.
                systemPrompt: opts?.systemPrompt,
              });
              synthesisRan = true;
              // OpenCode H1: re-check abort.signal.aborted after synthesis
              // returns. runAgentTeamSynthesis also does this, but we
              // double-check here in case the caller aborted between the
              // runner's post-abort check and this handler regaining control.
              if (teamCancelled || abort.signal.aborted) {
                dispatch({
                  type: 'warning',
                  message: `Synthesis cancelled mid-flight; falling back to winner's original diff.`,
                });
                winnerDiff = preSynthesisWinnerDiff;
                synthesisChanged = false;
              } else if (synthResult.ok) {
                // Codex M4: meter synthesis cost. runApiAgentLoop doesn't
                // expose token counts, so estimate from response length
                // (~4 chars/token). This is an under-estimate since it
                // misses tool-use output, but it's better than zero and
                // is capped by the synthesis timeout.
                const estTokens = Math.ceil((synthResult.responseExcerpt.length * 4) / 4) + 800;
                synthesisCostUsd = winnerEngine
                  ? estimatedTokensToCost(winnerEngine, estTokens)
                  : 0;
                if (synthResult.changed) {
                  synthesisChanged = true;
                  winnerDiff = synthResult.synthesizedDiff;
                  // Codex H1: post-synthesis fitness re-check via the
                  // extracted helper (testable). Reverts winnerDiff to
                  // the pre-synthesis value if fitness regressed.
                  const refit = await runPostSynthesisFitnessCheck({
                    worktreePath: winnerMember.worktreePath,
                    fitnessCmd: opts?.fitnessCmd ?? 'npm run typecheck',
                    timeoutSec: 90,
                    signal: abort.signal,
                  });
                  if (!refit.passed) {
                    synthesisFitnessRegressed = true;
                    winnerDiff = preSynthesisWinnerDiff;
                    synthesisChanged = false;
                    const why = refit.error
                      ? `re-check errored (${refit.error})`
                      : `fitness gate failed (exit ${refit.exitCode})`;
                    dispatch({
                      type: 'warning',
                      message: `Synthesis ${why}; reverted to original winner diff.`,
                    });
                  } else {
                    // OpenCode #5 prompt-bias signal: scan response excerpt
                    // for loser engineId mentions. Zero mentions + non-no-op
                    // diff suggests the model may have polished its own
                    // answer instead of incorporating loser insights.
                    const loserIds = losers.map((l) => l.engineId);
                    const biasSignal = detectSynthesisInsightMention({
                      responseExcerpt: synthResult.responseExcerpt,
                      loserEngineIds: loserIds,
                    });
                    if (!biasSignal.hasAnyMention && loserIds.length > 0) {
                      dispatch({
                        type: 'info',
                        message: `Synthesis summary did not explicitly mention any other engine by name (${loserIds.join(', ')}); the refinement may not have incorporated their insights directly.`,
                      });
                    }
                    dispatch({
                      type: 'success',
                      message: `Synthesis complete (diff updated, fitness re-verified${biasSignal.hasAnyMention ? ', cites ' + biasSignal.mentionedEngineIds.join('+') : ''})${synthResult.responseExcerpt ? ': ' + synthResult.responseExcerpt.slice(0, 160) : ''}`,
                    });
                  }
                } else {
                  dispatch({
                    type: 'info',
                    message: `Synthesis reviewed and kept original diff (no incorporable insights)`,
                  });
                }
              } else {
                // Codex H2/H3: runAgentTeamSynthesis now detects
                // empty-diff corruption + error-as-response + abort
                // races, so ok=false is a real failure signal.
                dispatch({
                  type: 'warning',
                  message: `Synthesis failed (${synthResult.error ?? 'unknown'}); falling back to winner's original diff.`,
                });
                winnerDiff = preSynthesisWinnerDiff;
                synthesisChanged = false;
              }
            } catch (synthErr: any) {
              dispatch({
                type: 'warning',
                message: `Synthesis errored (${synthErr?.message ?? String(synthErr)}); falling back to winner's original diff.`,
              });
              winnerDiff = preSynthesisWinnerDiff;
              synthesisChanged = false;
            }
          }
        } else if (taskKind === 'investigate' && winnerAnalysis !== null && winnerAnalysis.trim()) {
          // OpenCode #4 defensive check: the team-mode path always isolates
          // (so worktreePath should be set), but if the invariant broke we
          // fall back to cwd and log a warning so the drift is visible.
          const invCwd = winnerMember.worktreePath ?? cwd;
          if (!winnerMember.worktreePath) {
            dispatch({
              type: 'warning',
              message: `Team-mode invariant broke: winner ${winnerInfo.winner} has no worktreePath. Reconciliation running in ${cwd} (main repo) instead — edits here would affect the user's working tree. Consider this a bug signal.`,
            });
          }
          dispatch({
            type: 'info',
            message: `Reconciling: ${winnerInfo.winner} merging ${losers.length} other analys${losers.length === 1 ? 'is' : 'es'}...`,
          });
          try {
            const invResult = await runAgentInvestigateSynthesis({
              task: input,
              winnerEngineId: winnerInfo.winner,
              winnerApi,
              winnerCwd: invCwd,
              winnerResponse: winnerAnalysis,
              losers,
              timeout: opts?.synthesisTimeoutSec ?? 180,
              signal: abort.signal,
              maxSteps: 4,
              systemPrompt: opts?.systemPrompt,
            });
            synthesisRan = true;
            if (teamCancelled || abort.signal.aborted) {
              dispatch({
                type: 'warning',
                message: `Reconciliation cancelled mid-flight; falling back to winner's original report.`,
              });
              winnerAnalysis = preSynthesisWinnerAnalysis;
              synthesisChanged = false;
            } else if (invResult.ok) {
              const estTokens = Math.ceil(invResult.report.length) + 800;
              synthesisCostUsd = winnerEngine
                ? estimatedTokensToCost(winnerEngine, estTokens)
                : 0;
              synthesisChanged = invResult.report !== winnerAnalysis;
              winnerAnalysis = invResult.report;
              dispatch({
                type: 'success',
                message: `Reconciliation complete (${invResult.report.length} chars).`,
              });
            } else {
              dispatch({
                type: 'warning',
                message: `Reconciliation failed (${invResult.error ?? 'unknown'}); falling back to winner's original report.`,
              });
              winnerAnalysis = preSynthesisWinnerAnalysis;
              synthesisChanged = false;
            }
          } catch (synthErr: any) {
            dispatch({
              type: 'warning',
              message: `Reconciliation errored (${synthErr?.message ?? String(synthErr)}); falling back to winner's original report.`,
            });
            winnerAnalysis = preSynthesisWinnerAnalysis;
            synthesisChanged = false;
          }
        }
      }
    }

    // ── Persistent synthesis log (OpenCode #7) ───────────
    // Write a machine-parseable log of the synthesis outcome so users
    // can trace what happened post-mortem without relying on scrollback.
    // Lives alongside the winner patch at RUNS_DIR/team-agent-<id>/.
    if (synthesisRan) {
      try {
        const logDir = join(RUNS_DIR, `team-agent-${teamId}`);
        mkdirSync(logDir, { recursive: true });
        const logPath = join(logDir, 'synthesis.log');
        const logContent = JSON.stringify({
          teamId,
          timestamp: new Date().toISOString(),
          winner: winnerInfo.winner,
          taskKind,
          losersConsidered: teamResult.members
            .filter((m) => m.engineId !== winnerInfo.winner && m.stepResult)
            .map((m) => m.engineId),
          synthesisRan: true,
          synthesisChanged,
          synthesisFitnessRegressed,
          synthesisCostUsd,
          preSynthesisDiffLen: preSynthesisWinnerDiff?.length ?? 0,
          postSynthesisDiffLen: winnerDiff?.length ?? 0,
          preSynthesisAnalysisLen: preSynthesisWinnerAnalysis?.length ?? 0,
          postSynthesisAnalysisLen: winnerAnalysis?.length ?? 0,
        }, null, 2);
        writeFileSync(logPath, logContent);
      } catch (logErr) {
        // Log-write failure is non-fatal; just warn.
        console.warn(`[agon] failed to write synthesis log: ${logErr instanceof Error ? logErr.message : String(logErr)}`);
      }
    }

    // ── Compute team cost ────────────────────────────────
    // Includes synthesis cost (Codex M4) so teamCostUsd in the event
    // reflects true spend.
    let teamCost = synthesisCostUsd;
    for (const m of teamResult.members) {
      teamCost += costFn(m.engineId, m.stepResult?.tokensUsed ?? 0);
    }

    // ── Build member outcomes for the team-complete event ─
    const memberOutcomes = teamResult.members.map((m) => {
      const sr = scored.get(m.engineId);
      return {
        engineId: m.engineId,
        outcome: !m.stepResult ? 'failed' : m.stepResult.stopReason,
        diffLines: sr?.diffLines ?? 0,
        passedFitness: fitnessPassed.get(m.engineId) ?? false,
      };
    });

    // ── Emit team-complete ───────────────────────────────
    dispatch({
      type: 'agent-team-complete',
      teamId,
      winner: winnerInfo.winner,
      synthesizedPatch: winnerDiff,
      synthesizedAnalysis: winnerAnalysis,
      memberOutcomes,
      teamCostUsd: teamCost,
      teamDurationMs: teamResult.durationMs,
      synthesisRan,
      synthesisChanged,
      synthesisCostUsd,
      synthesisFitnessRegressed,
    });

    // Append winning team diff to the shared ContextThread so Cesar has
    // the full line-by-line trail of what the team built. teamThread is
    // the shared thread the team members were already writing into.
    if (teamThread && winnerInfo.winner && winnerDiff) {
      try {
        // Review #8: 90k chars aligns with MAX_PER_MESSAGE_TOKENS=30000
        // (≈ 120k chars cap, leave 25% headroom for surrounding text).
        const capped = winnerDiff.length > 90000
          ? winnerDiff.slice(0, 90000) + `\n\n[... ${winnerDiff.length - 90000} more chars truncated]`
          : winnerDiff;
        teamThread.append({
          role: 'assistant',
          content: `[agent-team-diff] winner: ${winnerInfo.winner} (score ${winnerInfo.bestScore})\n${capped}`,
        });
        await teamThread.save();
      } catch (err) {
        // Surface to user — silent degradation of memory is worse than noise.
        dispatch({ type: 'warning', message: `Team diff NOT persisted to thread: ${err instanceof Error ? err.message : String(err)}` });
      }
    } else if (teamThread && winnerAnalysis && taskKind === 'investigate') {
      // For investigate mode, the "diff" is the analysis text.
      try {
        teamThread.append({
          role: 'assistant',
          content: `[agent-team-analysis] winner: ${winnerInfo.winner}\n${winnerAnalysis}`,
        });
        await teamThread.save();
      } catch { /* non-fatal */ }
    }

    let patchPath = '';

    // ── Surface the result to the user ────────────────────
    if (winnerInfo.winner) {
      if (winnerDiff) {
        // Codex P3: persist the winning patch to a real file so
        // handleReviewAction('edit') opens the patch instead of an
        // empty buffer.
        try {
          const patchDir = join(RUNS_DIR, `team-agent-${teamId}`);
          mkdirSync(patchDir, { recursive: true });
          patchPath = join(patchDir, `${winnerInfo.winner}.patch`);
          writeFileSync(patchPath, winnerDiff);
        } catch (err) {
          const errMsg = err instanceof Error ? err.message : String(err);
          console.warn(`[agon] failed to persist team-agent winner patch: ${errMsg}`);
          patchPath = '';
          // Gemini fix (e): tell the user the [E]dit action is unavailable
          // so they don't hit an empty-buffer surprise on disk-full.
          dispatch({ type: 'warning', message: `Could not persist winning patch (${errMsg}). [E]dit action will be unavailable; the patch is still shown below.` });
        }
        dispatch({
          type: 'patch-review',
          winnerId: winnerInfo.winner,
          patchPath,
          patchContent: winnerDiff,
        } as any);
      } else if (winnerAnalysis) {
        dispatch({ type: 'engine-block', engineId: winnerInfo.winner, color: 0x9333ea, content: winnerAnalysis } as any);
      }
      dispatch({
        type: 'success',
        message: `Agent team complete \u2014 winner: ${winnerInfo.winner} | $${teamCost.toFixed(2)} | ${(teamResult.durationMs/1000).toFixed(0)}s`,
      });
    } else {
      // No winner — present all member responses inline so user can pick.
      for (const m of teamResult.members) {
        if (m.stepResult?.response) {
          dispatch({ type: 'engine-block', engineId: m.engineId, color: 0, content: m.stepResult.response } as any);
        }
      }
      dispatch({
        type: 'warning',
        message: `Agent team finished with no winner (no member passed the fitness gate). All ${teamResult.members.length} responses shown above.`,
      });
    }
    const memberSummary = memberOutcomes
      .map((m) => `${m.engineId}:${m.outcome}${m.passedFitness ? ' pass' : ' fail'}`)
      .join(', ');
    const teamSummaryLines = [
      `[team-agent] "${input.slice(0, 120)}" — ${winnerInfo.winner ? 'completed' : 'no-winner'}`,
      `Task kind: ${taskKind}`,
      `Winner: ${winnerInfo.winner ?? 'none'}`,
      `Members: ${memberSummary || 'none'}`,
      `Cost: $${teamCost.toFixed(2)}`,
      `Duration: ${(teamResult.durationMs / 1000).toFixed(0)}s`,
    ];
    if (taskKind === 'edit') {
      teamSummaryLines.push(
        winnerInfo.winner
          ? `Main workspace not changed automatically. Winner patch${patchPath ? `: ${patchPath}` : ' was not persisted to disk; use the patch-review block or thread diff.'}`
          : 'No winner patch available.'
      );
    } else if (winnerAnalysis) {
      teamSummaryLines.push(`Winning analysis:\n${clipAgentText(winnerAnalysis, 4000)}`);
    }
    const teamSummary = teamSummaryLines.join('\n');
    if (teamThread) {
      try {
        teamThread.append({ role: 'assistant', content: teamSummary });
        await teamThread.save();
      } catch { /* non-fatal */ }
    }
    followUp = {
      kind: 'team-agent',
      status: winnerInfo.winner ? 'completed' : 'no-winner',
      task: input,
      taskKind,
      summary: teamSummary,
      engineId: winnerInfo.winner ?? null,
      winnerId: winnerInfo.winner ?? null,
      response: taskKind === 'investigate' ? (clipAgentText(winnerAnalysis ?? '', 4000) || null) : null,
      patchPath: patchPath || null,
      patchAvailable: !!patchPath,
      workspaceChangedInPlace: false,
    };
  } catch (err: any) {
    dispatch({ type: 'error', message: `Agent team failed: ${err?.message ?? String(err)}` });
    const errMsg = err?.message ?? String(err);
    const summary = [
      `[team-agent] "${input.slice(0, 120)}" — failed`,
      `Task kind: ${taskKind}`,
      `Error: ${errMsg}`,
    ].join('\n');
    if (teamThread) {
      try {
        teamThread.append({ role: 'assistant', content: summary });
        await teamThread.save();
      } catch { /* non-fatal */ }
    }
    followUp = {
      kind: 'team-agent',
      status: 'failed',
      task: input,
      taskKind,
      summary,
      engineId: null,
      winnerId: null,
      response: null,
      patchPath: null,
      patchAvailable: false,
      workspaceChangedInPlace: false,
    };
  } finally {
    abort.signal.removeEventListener('abort', onAbort);
    if (onParentAbort && parentSignal) {
      try { parentSignal.removeEventListener('abort', onParentAbort); } catch { /* ignore */ }
    }
    // Codex P1: don't null the active abort if a parent owns it (plan step).
    if (!parentSignal) {
      ctx.setActiveAbort(null);
    }
    if (team) {
      try { await team.cleanup(); } catch (cleanupErr) {
        console.warn(`[agon] AgentTeam cleanup failed: ${cleanupErr instanceof Error ? cleanupErr.message : String(cleanupErr)}`);
      }
    }
  }
  return followUp;
}
